@dataclass
class Task:
    name: str
    fn: Callable
    run_at: float
    interval: Optional[float] = None  # None = one-shot, float = repeat every N seconds

class Scheduler:
    def __init__(self):
        self.tasks: List[Task] = []
        self.executed: List[str] = []

    def schedule(self, name: str, fn: Callable, delay: float = 0, interval: Optional[float] = None):
        self.tasks.append(Task(
            name=name, fn=fn,
            run_at=time.time() + delay,
            interval=interval,
        ))

    def tick(self):
        now = time.time()
        ready = [t for t in self.tasks if t.run_at <= now]
        for task in ready:
            task.fn()
            self.executed.append(task.name)
            self.tasks.remove(task)
            if task.interval is not None:
                # Re-enqueue recurring task
                self.tasks.append(Task(
                    name=task.name,
                    fn=task.fn,
                    run_at=now + task.interval,
                    interval=task.interval,
                ))
